// src/pages/PrintAgendamentos.jsx
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useLocation, useNavigate } from 'react-router-dom';

export default function PrintAgendamentos() {
  const location = useLocation();
  const navigate = useNavigate();
  const [agendamentos, setAgendamentos] = useState([]);
  const [loading, setLoading] = useState(true);

  const { disciplinaId, filtros } = location.state || {};

  useEffect(() => {
    async function fetchData() {
      try {
        setLoading(true);
        const params = {};
        if (disciplinaId) params.disciplinaId = disciplinaId;
        if (filtros?.data) params.data = filtros.data;
        if (filtros?.hora) params.hora = filtros.hora;
        if (filtros?.busca) params.busca = filtros.busca;

        const res = await axios.get('/api/agendamentos', { params });
        setAgendamentos(res.data);
      } catch (err) {
        console.error('Erro ao buscar agendamentos para impressão:', err);
      } finally {
        setLoading(false);
      }
    }
    fetchData();
  }, [disciplinaId, filtros]);

  useEffect(() => {
    if (!loading) {
      setTimeout(() => {
        window.print();
        navigate(-1);
      }, 200);
    }
  }, [loading, navigate]);

  if (loading) {
    return (
      <div className="p-8">
        <p>Preparando impressão...</p>
      </div>
    );
  }

  return (
    <div className="printable bg-white p-8">
      <h2 className="text-2xl font-bold mb-4">Lista de Agendamentos</h2>
      {disciplinaId && (
        <p className="text-gray-700 mb-2">
          <span className="font-semibold">Disciplina ID:</span> {disciplinaId}
        </p>
      )}

      <div className="overflow-x-auto">
        <table className="min-w-full bg-white divide-y divide-gray-200 rounded-lg shadow-sm">
          <thead className="bg-gray-100">
            <tr>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-600 uppercase">N°</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-600 uppercase">Operador</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-600 uppercase">Auxiliar</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-600 uppercase">Disciplina</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-600 uppercase">Paciente</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-600 uppercase">Telefone</th>
              <th className="px-4 py-2 text-left text-xs font-medium text-gray-600 uppercase">Status</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-200">
            {agendamentos.map((ag, idx) => (
              <tr key={ag.id || idx} className="hover:bg-gray-50">
                <td className="px-4 py-2 text-sm text-gray-800">{idx + 1}</td>
                <td className="px-4 py-2 text-sm text-gray-800">{ag.operadorNome || '-'}</td>
                <td className="px-4 py-2 text-sm text-gray-800">{ag.auxiliarNome || '-'}</td>
                <td className="px-4 py-2 text-sm text-gray-800">{ag.disciplinaNome || '-'}</td>
                <td className="px-4 py-2 text-sm text-gray-800">{ag.pacienteNome || '-'}</td>
                <td className="px-4 py-2 text-sm text-gray-800">{ag.telefone || '-'}</td>
                <td className="px-4 py-2 text-sm text-gray-800">
                  {ag.data ? ag.data.slice(0, 10).split('-').reverse().join('/') : '-'}
                </td>
                <td className="px-4 py-2 text-sm text-gray-800">{ag.hora || '-'}</td>
                <td className="px-4 py-2 text-sm text-gray-800">{ag.status || '-'}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <style>{`
        @media print {
          body * { visibility: hidden; }
          .printable, .printable * { visibility: visible !important; }
          .printable { position: absolute; top: 0; left: 0; width: 100vw; }
        }
      `}</style>
    </div>
  );
}
